/*
  MiniXLSX: lector/exportador XLSX mínimo para esta calculadora.
  No es SheetJS completo. Implementa solo lo necesario para leer hojas simples
  y exportar libros .xlsx reimportables sin backend ni Node.js.
*/
(function (global) {
  "use strict";

  const textEncoder = new TextEncoder();
  const textDecoder = new TextDecoder("utf-8");

  function u16(view, offset) { return view.getUint16(offset, true); }
  function u32(view, offset) { return view.getUint32(offset, true); }

  function encodeText(text) { return textEncoder.encode(String(text ?? "")); }
  function decodeText(bytes) { return textDecoder.decode(bytes); }

  function xmlEscape(value) {
    return String(value ?? "")
      .replace(/&/g, "&amp;")
      .replace(/</g, "&lt;")
      .replace(/>/g, "&gt;")
      .replace(/"/g, "&quot;")
      .replace(/'/g, "&apos;");
  }

  function xmlUnescape(value) {
    const txt = document.createElement("textarea");
    txt.innerHTML = value;
    return txt.value;
  }

  const crcTable = (() => {
    const table = new Uint32Array(256);
    for (let i = 0; i < 256; i++) {
      let c = i;
      for (let k = 0; k < 8; k++) c = (c & 1) ? (0xedb88320 ^ (c >>> 1)) : (c >>> 1);
      table[i] = c >>> 0;
    }
    return table;
  })();

  function crc32(bytes) {
    let crc = 0xffffffff;
    for (let i = 0; i < bytes.length; i++) crc = crcTable[(crc ^ bytes[i]) & 0xff] ^ (crc >>> 8);
    return (crc ^ 0xffffffff) >>> 0;
  }

  async function inflateRaw(bytes) {
    if (typeof DecompressionStream === "undefined") {
      throw new Error("Este navegador no permite descomprimir XLSX comprimidos. Usa Chrome/Edge moderno o importa un Excel exportado por esta app.");
    }
    const stream = new Blob([bytes]).stream().pipeThrough(new DecompressionStream("deflate-raw"));
    const result = await new Response(stream).arrayBuffer();
    return new Uint8Array(result);
  }

  async function unzip(arrayBuffer) {
    const bytes = new Uint8Array(arrayBuffer);
    const view = new DataView(arrayBuffer);
    let eocd = -1;
    for (let i = bytes.length - 22; i >= Math.max(0, bytes.length - 66000); i--) {
      if (u32(view, i) === 0x06054b50) { eocd = i; break; }
    }
    if (eocd < 0) throw new Error("Archivo XLSX inválido: no se encontró el índice ZIP.");

    const entriesCount = u16(view, eocd + 10);
    const centralOffset = u32(view, eocd + 16);
    const files = {};
    let ptr = centralOffset;

    for (let i = 0; i < entriesCount; i++) {
      if (u32(view, ptr) !== 0x02014b50) throw new Error("Archivo XLSX inválido: entrada central corrupta.");
      const method = u16(view, ptr + 10);
      const compressedSize = u32(view, ptr + 20);
      const nameLen = u16(view, ptr + 28);
      const extraLen = u16(view, ptr + 30);
      const commentLen = u16(view, ptr + 32);
      const localOffset = u32(view, ptr + 42);
      const filename = decodeText(bytes.slice(ptr + 46, ptr + 46 + nameLen));

      if (u32(view, localOffset) !== 0x04034b50) throw new Error("Archivo XLSX inválido: entrada local corrupta.");
      const localNameLen = u16(view, localOffset + 26);
      const localExtraLen = u16(view, localOffset + 28);
      const dataStart = localOffset + 30 + localNameLen + localExtraLen;
      const compressed = bytes.slice(dataStart, dataStart + compressedSize);
      let data;
      if (method === 0) data = compressed;
      else if (method === 8) data = await inflateRaw(compressed);
      else throw new Error(`Método ZIP no soportado: ${method}`);
      files[filename.replace(/^\//, "")] = data;
      ptr += 46 + nameLen + extraLen + commentLen;
    }
    return files;
  }

  function parseXml(text) {
    const parser = new DOMParser();
    const doc = parser.parseFromString(text, "application/xml");
    const error = doc.querySelector("parsererror");
    if (error) throw new Error("XML inválido dentro del XLSX.");
    return doc;
  }

  function getAttr(node, name) {
    return node.getAttribute(name) || node.getAttribute(`r:${name}`) || "";
  }

  function colToIndex(col) {
    let n = 0;
    for (const ch of col.toUpperCase()) n = n * 26 + (ch.charCodeAt(0) - 64);
    return n - 1;
  }

  function cellRefToPosition(ref) {
    const match = String(ref || "").match(/^([A-Z]+)(\d+)$/i);
    if (!match) return null;
    return { col: colToIndex(match[1]), row: Number(match[2]) - 1 };
  }

  function getTextContent(node) {
    return Array.from(node.querySelectorAll("t")).map(t => t.textContent || "").join("");
  }

  function readSharedStrings(files) {
    const file = files["xl/sharedStrings.xml"];
    if (!file) return [];
    const doc = parseXml(decodeText(file));
    return Array.from(doc.getElementsByTagName("si")).map(si => getTextContent(si));
  }

  function resolveTarget(target) {
    const clean = String(target || "").replace(/^\//, "");
    if (clean.startsWith("xl/")) return clean;
    return `xl/${clean}`.replace(/\/\.\//g, "/");
  }

  function parseSheet(fileBytes, sharedStrings) {
    const doc = parseXml(decodeText(fileBytes));
    const rows = [];
    const rowNodes = Array.from(doc.getElementsByTagName("row"));
    for (const rowNode of rowNodes) {
      const rowNumber = Number(rowNode.getAttribute("r") || rows.length + 1) - 1;
      if (!rows[rowNumber]) rows[rowNumber] = [];
      const cells = Array.from(rowNode.getElementsByTagName("c"));
      for (const cell of cells) {
        const pos = cellRefToPosition(cell.getAttribute("r"));
        if (!pos) continue;
        const type = cell.getAttribute("t") || "";
        let value = "";
        if (type === "inlineStr") {
          const is = cell.getElementsByTagName("is")[0];
          value = is ? getTextContent(is) : "";
        } else {
          const v = cell.getElementsByTagName("v")[0];
          value = v ? v.textContent || "" : "";
          if (type === "s") value = sharedStrings[Number(value)] ?? "";
          else if (type === "b") value = value === "1";
          else if (value !== "" && !Number.isNaN(Number(value))) value = Number(value);
        }
        if (!rows[pos.row]) rows[pos.row] = [];
        rows[pos.row][pos.col] = value;
      }
    }
    return rows.map(row => row || []);
  }

  async function readArrayBuffer(arrayBuffer) {
    const files = await unzip(arrayBuffer);
    const workbookFile = files["xl/workbook.xml"];
    const relsFile = files["xl/_rels/workbook.xml.rels"];
    if (!workbookFile || !relsFile) throw new Error("El XLSX no contiene workbook.xml.");

    const workbookDoc = parseXml(decodeText(workbookFile));
    const relsDoc = parseXml(decodeText(relsFile));
    const rels = {};
    Array.from(relsDoc.getElementsByTagName("Relationship")).forEach(rel => {
      rels[rel.getAttribute("Id")] = resolveTarget(rel.getAttribute("Target"));
    });

    const sharedStrings = readSharedStrings(files);
    const result = { SheetNames: [], Sheets: {} };
    const sheetNodes = Array.from(workbookDoc.getElementsByTagName("sheet"));
    for (const sheet of sheetNodes) {
      const name = sheet.getAttribute("name") || `Sheet${result.SheetNames.length + 1}`;
      const rid = getAttr(sheet, "id");
      const path = rels[rid];
      if (!path || !files[path]) continue;
      result.SheetNames.push(name);
      result.Sheets[name] = parseSheet(files[path], sharedStrings);
    }
    return result;
  }

  function columnName(index) {
    let n = index + 1;
    let s = "";
    while (n > 0) {
      const m = (n - 1) % 26;
      s = String.fromCharCode(65 + m) + s;
      n = Math.floor((n - m) / 26);
    }
    return s;
  }

  function sheetXml(rows) {
    const safeRows = Array.isArray(rows) ? rows : [];
    const xmlRows = safeRows.map((row, rIndex) => {
      const cells = (Array.isArray(row) ? row : []).map((value, cIndex) => {
        if (value === undefined || value === null || value === "") return "";
        const ref = `${columnName(cIndex)}${rIndex + 1}`;
        if (typeof value === "number" && Number.isFinite(value)) {
          return `<c r="${ref}"><v>${value}</v></c>`;
        }
        if (typeof value === "boolean") {
          return `<c r="${ref}" t="b"><v>${value ? 1 : 0}</v></c>`;
        }
        return `<c r="${ref}" t="inlineStr"><is><t>${xmlEscape(value)}</t></is></c>`;
      }).join("");
      return `<row r="${rIndex + 1}">${cells}</row>`;
    }).join("");
    return `<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<worksheet xmlns="http://schemas.openxmlformats.org/spreadsheetml/2006/main" xmlns:r="http://schemas.openxmlformats.org/officeDocument/2006/relationships"><sheetData>${xmlRows}</sheetData></worksheet>`;
  }

  function buildFiles(sheets) {
    const cleanSheets = (sheets || []).map((sheet, index) => ({
      name: String(sheet.name || `Sheet${index + 1}`).slice(0, 31).replace(/[\\/?*\[\]:]/g, " ").trim() || `Sheet${index + 1}`,
      rows: sheet.rows || []
    }));
    const overrides = cleanSheets.map((_, i) => `<Override PartName="/xl/worksheets/sheet${i + 1}.xml" ContentType="application/vnd.openxmlformats-officedocument.spreadsheetml.worksheet+xml"/>`).join("");
    const sheetDefs = cleanSheets.map((sheet, i) => `<sheet name="${xmlEscape(sheet.name)}" sheetId="${i + 1}" r:id="rId${i + 1}"/>`).join("");
    const relDefs = cleanSheets.map((_, i) => `<Relationship Id="rId${i + 1}" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/worksheet" Target="worksheets/sheet${i + 1}.xml"/>`).join("");
    const files = {
      "[Content_Types].xml": `<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Types xmlns="http://schemas.openxmlformats.org/package/2006/content-types"><Default Extension="rels" ContentType="application/vnd.openxmlformats-package.relationships+xml"/><Default Extension="xml" ContentType="application/xml"/><Override PartName="/xl/workbook.xml" ContentType="application/vnd.openxmlformats-officedocument.spreadsheetml.sheet.main+xml"/>${overrides}</Types>`,
      "_rels/.rels": `<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships"><Relationship Id="rId1" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/officeDocument" Target="xl/workbook.xml"/></Relationships>`,
      "xl/workbook.xml": `<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<workbook xmlns="http://schemas.openxmlformats.org/spreadsheetml/2006/main" xmlns:r="http://schemas.openxmlformats.org/officeDocument/2006/relationships"><sheets>${sheetDefs}</sheets></workbook>`,
      "xl/_rels/workbook.xml.rels": `<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships">${relDefs}</Relationships>`
    };
    cleanSheets.forEach((sheet, i) => { files[`xl/worksheets/sheet${i + 1}.xml`] = sheetXml(sheet.rows); });
    return files;
  }

  function pushU16(arr, value) { arr.push(value & 0xff, (value >>> 8) & 0xff); }
  function pushU32(arr, value) { arr.push(value & 0xff, (value >>> 8) & 0xff, (value >>> 16) & 0xff, (value >>> 24) & 0xff); }
  function pushBytes(arr, bytes) { for (const b of bytes) arr.push(b); }

  function makeZip(files) {
    const localParts = [];
    const centralParts = [];
    let offset = 0;
    for (const [name, text] of Object.entries(files)) {
      const nameBytes = encodeText(name);
      const data = encodeText(text);
      const crc = crc32(data);
      const local = [];
      pushU32(local, 0x04034b50);
      pushU16(local, 20);
      pushU16(local, 0x0800);
      pushU16(local, 0);
      pushU16(local, 0);
      pushU16(local, 0);
      pushU32(local, crc);
      pushU32(local, data.length);
      pushU32(local, data.length);
      pushU16(local, nameBytes.length);
      pushU16(local, 0);
      pushBytes(local, nameBytes);
      pushBytes(local, data);
      localParts.push(...local);

      const central = [];
      pushU32(central, 0x02014b50);
      pushU16(central, 20);
      pushU16(central, 20);
      pushU16(central, 0x0800);
      pushU16(central, 0);
      pushU16(central, 0);
      pushU16(central, 0);
      pushU32(central, crc);
      pushU32(central, data.length);
      pushU32(central, data.length);
      pushU16(central, nameBytes.length);
      pushU16(central, 0);
      pushU16(central, 0);
      pushU16(central, 0);
      pushU16(central, 0);
      pushU32(central, 0);
      pushU32(central, offset);
      pushBytes(central, nameBytes);
      centralParts.push(...central);
      offset += local.length;
    }
    const centralOffset = localParts.length;
    const centralSize = centralParts.length;
    const eocd = [];
    pushU32(eocd, 0x06054b50);
    pushU16(eocd, 0);
    pushU16(eocd, 0);
    pushU16(eocd, Object.keys(files).length);
    pushU16(eocd, Object.keys(files).length);
    pushU32(eocd, centralSize);
    pushU32(eocd, centralOffset);
    pushU16(eocd, 0);
    return new Uint8Array([...localParts, ...centralParts, ...eocd]);
  }

  function writeWorkbook(sheets) {
    return makeZip(buildFiles(sheets));
  }

  function downloadBlob(blob, filename) {
    const url = URL.createObjectURL(blob);
    const a = document.createElement("a");
    a.href = url;
    a.download = filename;
    document.body.appendChild(a);
    a.click();
    a.remove();
    URL.revokeObjectURL(url);
  }

  function writeFile(filename, sheets) {
    const bytes = writeWorkbook(sheets);
    downloadBlob(new Blob([bytes], { type: "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet" }), filename);
  }

  global.MiniXLSX = {
    readArrayBuffer,
    writeWorkbook,
    writeFile,
    xmlEscape,
    xmlUnescape
  };
})(window);
